const staticData = $getWorkflowStaticData('global');
const numero = $json.body.data.key.remoteJid;
const mensagem = ($json.body.data.message.conversation || '').trim();
if (!staticData.estados) staticData.estados = {};

if (mensagem === '*fim*') {
  return [{ json: { numero, mensagem, acao: 'encerrar_manual' } }];
}

const dados = staticData.estados[numero];
if (!dados) {
  staticData.estados[numero] = { estado: 'atendente_iniciou', timestamp: Date.now(), avisado: false };
  return [{ json: { numero, mensagem, acao: 'ignorar' } }];
}

const estado = typeof dados === 'string' ? dados : dados.estado;
if (estado === 'aguardando_atendente' || estado === 'atendente_iniciou') {
  staticData.estados[numero] = { estado: 'aguardando_cliente', timestamp: Date.now(), avisado: false };
}

return [{ json: { numero, mensagem, acao: 'normal' } }];

