const staticData = $getWorkflowStaticData('global');
const numero = $('Verificar Estado').item.json.numero;
if (!staticData.estados) staticData.estados = {};
staticData.estados[numero] = { estado: 'aguardando_atendente', timestamp: Date.now(), avisado: false };
return [{ json: { ok: true } }];

const staticData = $getWorkflowStaticData('global');
const numero = $('Webhook').item.json.body.data.key.remoteJid;
if (!staticData.estados) staticData.estados = {};
staticData.estados[numero] = { estado: 'menu_enviado', timestamp: Date.now(), avisado: false };
return [{ json: { ok: true } }];

const staticData = $getWorkflowStaticData('global');
const agora = Date.now();
const TRES_HORAS = 3 * 60 * 60 * 1000;
const QUINZE_MIN = 15 * 60 * 1000;
const UM_DIA = 24 * 60 * 60 * 1000;
const BRT_OFFSET = -3 * 60 * 60 * 1000;

if (!staticData.estados) staticData.estados = {};
if (!staticData.filaRetorno) staticData.filaRetorno = {};

const brt = new Date(agora + BRT_OFFSET);
const hora = brt.getUTCHours();
const dia = brt.getUTCDay();
const horarioComercial = dia >= 1 && dia <= 5 && hora >= 8 && hora < 18;

const paraEnviarMenu = [];
const paraAvisar = [];
const paraEncerrar = [];

if (horarioComercial && Object.keys(staticData.filaRetorno).length > 0) {
  for (const [numero] of Object.entries(staticData.filaRetorno)) {
    const dadosAtivos = staticData.estados[numero];
    const estadoAtivo = dadosAtivos ? (typeof dadosAtivos === 'string' ? dadosAtivos : dadosAtivos.estado) : null;
    if (!estadoAtivo || estadoAtivo === 'menu_enviado') {
      paraEnviarMenu.push({ numero, acao: 'menu_retorno' });
    }
    delete staticData.filaRetorno[numero];
  }
}

for (const [numero, dados] of Object.entries(staticData.estados)) {
  if (typeof dados === 'string') continue;
  const { estado, timestamp, avisado } = dados;
  const inativo = agora - timestamp;

  if (estado === 'aguardando_atendente' || estado === 'atendente_iniciou') {
    if (horarioComercial && !avisado && inativo >= TRES_HORAS) {
      staticData.estados[numero].avisado = true;
      paraAvisar.push({ numero, acao: 'avisar_espera' });
    }
  } else if (estado === 'aguardando_cliente') {
    if (horarioComercial) {
      if (!avisado && inativo >= TRES_HORAS) {
        staticData.estados[numero].avisado = true;
        staticData.estados[numero].timestamp = Date.now();
        paraAvisar.push({ numero, acao: 'avisar_cliente' });
      } else if (avisado && inativo >= QUINZE_MIN) {
        delete staticData.estados[numero];
        paraEncerrar.push({ numero, acao: 'encerrar' });
      }
    }
  } else if (estado === 'menu_enviado' || estado === 'fora_horario_menu') {
    if (inativo >= UM_DIA) {
      delete staticData.estados[numero];
    }
  }
}

const resultado = [
  ...paraEnviarMenu.map(n => ({ json: n })),
  ...paraAvisar.map(n => ({ json: n })),
  ...paraEncerrar.map(n => ({ json: n }))
];

return resultado.length > 0 ? resultado : [{ json: { vazio: true } }];

